using UnityEngine;
using System.Text;
public class Script
{
    public static object Main()
    {
        var sb = new StringBuilder();
        var animals = Object.FindObjectsOfType<FL.Gameplay.Modules.BigWorld.AnimalController>();
        // 找玩家位置
        var cam = Camera.main;
        Vector3 playerPos = cam != null ? cam.transform.position : Vector3.zero;
        sb.AppendLine("CamPos=" + playerPos);
        sb.AppendLine("Animals: " + animals.Length);
        foreach (var a in animals)
        {
            float dist = Vector3.Distance(a.transform.position, playerPos);
            sb.AppendLine("  NetId=" + a.NetId + " pos=" + a.transform.position + " dist=" + dist.ToString("F1"));
        }
        return sb.ToString();
    }
}
